mapper.sql:
a.recycle = 0 AND a.mch_status = 2 AND a.STATUS = 2 AND a.commodity_type = '0' AND a.is_presell = 0 AND a.gongyingshang = '' AND a.num > 0 and a.store_id = #{storeId} and a.mch_id = #{mchId} and a.brand_id = #{brandId} AND a.product_class like CONCAT('%-', #{classId},'-%')
#{proId}
and (a.product_title like concat('%', #{key},'%') or a.id =#{key})

mapper.select:
SELECT a.id, a.goodsName, a.product_class, a.brand_id, a.mch_id, a.attrId, a.num, a.imgUrl, a.price, a.attribute, a.stockNum, a.mchName, a.brandName FROM ( SELECT a.id, a.product_title AS goodsName, a.product_class, a.brand_id, a.mch_id, c.id AS attrId, a.num, a.imgurl AS imgUrl, c.price, c.attribute, c.num AS stockNum, b.name AS mchName, brand.brand_name AS brandName, ROW_NUMBER() over (partition by a.id) AS top FROM lkt_product_list AS a LEFT JOIN lkt_mch AS b ON a.mch_id = b.id LEFT JOIN lkt_configure AS c ON a.id = c.pid LEFT JOIN lkt_brand_class brand ON brand.brand_id = a.brand_id
a.id ASC
) AS a WHERE a.top = 1 limit #{pageStart},#{pageEnd}
